import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import LoadingSpinner from '../shared/LoadingSpinner';
import AlertMessage from '../shared/AlertMessage';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

const CertificateViewerPage = () => {
  const { t } = useTranslation();
  const { id, templateName } = useParams();
  const [certificateSvgUrl, setCertificateSvgUrl] = useState(null);
  const [certificate, setCertificate] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  async function svgUrlToBase64(url) {
    try {
      const response = await fetch(url);
      if (!response.ok) {
        console.warn(`Failed to fetch SVG for base64 conversion: ${url}, status: ${response.status}`);
        // Return a minimal placeholder or empty string to avoid breaking the entire certificate
        return `data:image/svg+xml;utf8,${encodeURIComponent('<svg width="100" height="100"><text x="10" y="50">Error</text></svg>')}`;
      }
      const text = await response.text();
      const encoded = encodeURIComponent(text).replace(/'/g, '%27').replace(/"/g, '%22');
      return `data:image/svg+xml;utf8,${encoded}`;
    } catch (err) {
      console.warn(`Error fetching SVG for base64 conversion: ${url}`, err);
      return `data:image/svg+xml;utf8,${encodeURIComponent('<svg width="100" height="100"><text x="10" y="50">Error</text></svg>')}`;
    }
  }

  function formatDateEn(dateString) {
    if (!dateString) return '';
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
  }

  async function getCertificateSVG(cert) {
    if (!cert) return '';
    const origin = window.location.origin;

    // Fetch all images required for the new template
    const academyLogoBase64 = await svgUrlToBase64(`${origin}/images/logo/placeholder-academy-logo.svg`);
    const officialSealBase64 = await svgUrlToBase64(`${origin}/images/logo/official-academy-seal.svg`);
    // Assuming signatures are still relevant and their paths are correct
    // If signature images are specific to the new design, update paths here.
    // For now, using generic names as in the static template for placeholders.
    // const presidentSignBase64 = await svgUrlToBase64(`${origin}/images/signatures/linda-foster-signature.svg`);
    // const directorSignBase64 = await svgUrlToBase64(`${origin}/images/signatures/james-carpenter-signature.svg`);

    // Define colors and styles (consistent with the new SVG template)
    const goldColor = '#B08D57';
    const mainTextColor = '#333333';
    const recipientColor = '#000000';
    const smTextColor = '#555555';
    const backgroundColor = '#FFFEF0';
    const patternLineColor = '#EAE0D0'; // For the anti-counterfeit pattern

    // Certificate data with fallbacks
    const recipientName = cert.recipientName || cert.name || 'Recipient Name';
    const program = cert.program || cert.course || 'Program Name';
    const issueDate = formatDateEn(cert.issueDate || cert.date || new Date());
    const certificateId = cert.certificateNumber || cert.certificateId || 'N/A';

    // SVG structure based on the new template
    let svg = `<?xml version="1.0" encoding="UTF-8"?>
<svg width="1200" height="900" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <style>
    .title-gold { fill: ${goldColor}; font-family: "Times New Roman", serif; }
    .text-main { fill: ${mainTextColor}; font-family: "Times New Roman", serif; }
    .text-recipient { fill: ${recipientColor}; font-family: "Times New Roman", serif; font-weight: bold; }
    .text-sm { fill: ${smTextColor}; font-family: "Times New Roman", serif; }
    .signature-name { font-family: cursive; font-size: 28px; fill: ${mainTextColor}; }
  </style>

  <defs>
    <pattern id="antiCounterfeitPattern" patternUnits="userSpaceOnUse" width="10" height="10" patternTransform="rotate(45)">
      <path d="M-2,5 l14,-14 M-2,15 l14,-14 M-2,-5 l14,-14" style="stroke:${patternLineColor}; stroke-width:0.5"/>
    </pattern>
    <path id="star" d="M50,0 L61.2,35.4 L97.6,35.4 L68.2,57.3 L79.4,92.7 L50,70.8 L20.6,92.7 L31.8,57.3 L2.4,35.4 L38.8,35.4 Z" fill="${goldColor}" transform="scale(0.2)"/>
  </defs>

  <rect width="1200" height="900" fill="${backgroundColor}"/>
  <rect width="1200" height="900" fill="url(#antiCounterfeitPattern)"/>
  <rect x="15" y="15" width="1170" height="870" fill="none" stroke="${goldColor}" stroke-width="1" />

  ${academyLogoBase64 ? `<image x="550" y="50" width="100" height="100" xlink:href="${academyLogoBase64}" />` : ''}

  <text x="600" y="190" class="text-main" font-size="28" text-anchor="middle">ACADEMY EUROPE OPEN UNIVERSITY</text>

  <use xlink:href="#star" x="350" y="230" />
  <use xlink:href="#star" x="810" y="230" />
  <use xlink:href="#star" x="280" y="330" />
  <use xlink:href="#star" x="880" y="330" />
  <use xlink:href="#star" x="580" y="480" />
  
  <text x="600" y="280" class="title-gold" font-size="48" font-weight="bold" text-anchor="middle">DIPLOMA</text>

  <text x="600" y="350" class="text-main" font-size="18" text-anchor="middle">This is to certify that</text>
  <text x="600" y="410" class="text-recipient" font-size="36" text-anchor="middle">${recipientName}</text>
  <text x="600" y="460" class="text-main" font-size="18" text-anchor="middle">has successfully completed the online degree</text>
  <text x="600" y="520" class="title-gold" font-size="30" font-style="italic" font-weight="bold" text-anchor="middle">${program}</text>
  <text x="600" y="570" class="text-main" font-size="18" text-anchor="middle" dominant-baseline="middle">
    together with all the rights, privileges and honours which appertain thereto.
  </text>

  <text x="600" y="630" class="text-main" font-size="18" text-anchor="middle">Awarded Date</text>
  <text x="600" y="660" class="text-main" font-size="20" font-weight="bold" text-anchor="middle">${issueDate}</text>

  <!-- Signatures (using text placeholders as in static template) -->
  <g transform="translate(200, 720)">
    <!-- Actual signature images could be used here if available -->
    <!-- For now, matching static template's text-based approach -->
    <text x="0" y="0" class="signature-name">Linda Foster</text>
    <line x1="-20" y1="15" x2="180" y2="15" stroke="${goldColor}" stroke-width="1"/>
    <text x="80" y="45" class="text-sm" font-size="14" text-anchor="middle">Prof.Dr.Linda Foster</text>
    <text x="80" y="65" class="text-sm" font-size="14" text-anchor="middle">Manager – MBA Program, AEU</text>
  </g>

  <g transform="translate(800, 720)">
    <text x="0" y="0" class="signature-name">James Carpenter</text>
    <line x1="-20" y1="15" x2="200" y2="15" stroke="${goldColor}" stroke-width="1"/>
    <text x="90" y="45" class="text-sm" font-size="14" text-anchor="middle">Prof.Dr.James Carpenter</text>
    <text x="90" y="65" class="text-sm" font-size="14" text-anchor="middle">Director – MBA Program, AEU</text>
  </g>

  ${officialSealBase64 ? `<image x="550" y="700" width="100" height="100" xlink:href="${officialSealBase64}" />` : ''}
  <text x="600" y="825" font-family="SimSun, serif" font-size="16" text-anchor="middle" fill="#444444">官方认证电子签章</text>
  
  <text x="600" y="860" class="text-sm" font-size="12" text-anchor="middle">Certificate ID: ${certificateId}</text>
</svg>`;
    return svg;
  }

  useEffect(() => {
    const loadCertificate = async () => {
      setLoading(true);
      setError(null);
      try {
        const isEmbedRoute = window.location.pathname.includes('certificate-embed');
        let response;
        
        if (isEmbedRoute) {
          response = await fetch(`/api/certificates/verify/${id}`);
        } else {
          const token = localStorage.getItem('auth_token');
          if (!token) {
            // This error should ideally redirect to login or show a specific UI message
            setError(t('certificateViewer.authRequiredError')); // Using i18n key
            setLoading(false);
            return;
          }
          response = await fetch(`/api/certificates/${id}`, {
            headers: { Authorization: `Bearer ${token}` }
          });
        }
        
        if (!response.ok) {
          const errorData = await response.json().catch(() => ({ message: response.statusText }));
          throw new Error(errorData.message || `HTTP error ${response.status}`);
        }
        
        const data = await response.json();
        const cert = data.data;
        
        if (!cert) {
          throw new Error(t('certificateViewer.notFoundError')); // Using i18n key
        }

        setCertificate(cert);
        const svgContent = await getCertificateSVG(cert);
        const blob = new Blob([svgContent], { type: 'image/svg+xml' });
        const processedImageUrl = URL.createObjectURL(blob);
        setCertificateSvgUrl(processedImageUrl);

      } catch (err) {
        console.error(t('certificateViewer.loadError'), err); // Using i18n key
        setError(err.message || t('certificateViewer.genericLoadError')); // Using i18n key
      } finally {
        setLoading(false);
      }
    };

    if (id) {
      loadCertificate();
    }
    
    return () => {
      if (certificateSvgUrl) {
        URL.revokeObjectURL(certificateSvgUrl);
      }
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [id, t]); // Added 't' to dependencies as it's used in error messages

  const handleDownloadPDF = async () => {
    if (!certificate || !certificateSvgUrl) {
      alert(t('certificateViewer.pdf.generationError.noCertificate')); // i18n
      return;
    }
    
    const pdfLoadingMessage = t('certificateViewer.pdf.loadingMessage'); // i18n
    // You might want to show a loading indicator to the user here
    alert(pdfLoadingMessage); // Simple alert, consider a modal or toast

    try {
      // Create a temporary off-screen div to render the SVG for html2canvas
      let certRenderDiv = document.createElement('div');
      certRenderDiv.style.position = 'absolute';
      certRenderDiv.style.left = '-9999px'; // Off-screen
      certRenderDiv.style.width = '1200px'; // SVG width
      certRenderDiv.style.height = '900px'; // SVG height
      document.body.appendChild(certRenderDiv);

      // Fetch the SVG content again or use existing certificateSvgUrl if it's a data URL
      // For simplicity, regenerating SVG string to ensure all assets are freshly processed if needed
      const svgString = await getCertificateSVG(certificate);
      certRenderDiv.innerHTML = svgString;
      const svgElement = certRenderDiv.querySelector('svg');

      if (!svgElement) {
        throw new Error(t('certificateViewer.pdf.generationError.svgElementMissing')); // i18n
      }

      const canvas = await html2canvas(svgElement, {
        scale: 3, // Increased scale for better PDF quality
        useCORS: true,
        backgroundColor: backgroundColor, // Use the actual background color
        logging: false,
        imageTimeout: 20000, // Increased timeout
        onclone: (clonedDoc) => {
            // Ensure styles are applied in the cloned document if any are external or complex
            // For inline styles and SVG, this might not be strictly necessary but good for robustness
            const clonedSvg = clonedDoc.querySelector('svg');
            if(clonedSvg) {
                // Any specific manipulations on the cloned SVG before rendering if needed
            }
        }
      });
      
      document.body.removeChild(certRenderDiv); // Clean up the temporary div

      const imgData = canvas.toDataURL('image/png', 1.0);
      const pdf = new jsPDF({
        orientation: 'landscape',
        unit: 'px', // Using pixels to match canvas dimensions more easily
        format: [1200, 900], // Using SVG dimensions for PDF page size
        compress: true,
      });
      
      pdf.setProperties({
        title: `${certificate.recipientName || certificate.name} - ${certificate.program || certificate.course}`,
        subject: t('certificateViewer.pdf.subject'), // i18n
        author: t('certificateViewer.pdf.author'), // i18n
        creator: t('certificateViewer.pdf.creator'), // i18n
      });
      
      // Watermark (optional, can be adjusted or removed)
      // const addWatermark = () => {
      //   pdf.saveGraphicsState();
      //   pdf.setTextColor(150, 150, 150);
      //   pdf.setGState(new pdf.GState({opacity: 0.1})); // More subtle watermark
      //   pdf.setFontSize(60);
      //   pdf.text('ACADEMY EUROPE', pdf.internal.pageSize.getWidth() / 2, pdf.internal.pageSize.getHeight() / 2, { angle: -45, align: 'center' });
      //   pdf.restoreGraphicsState();
      // };
      // addWatermark();
      
      pdf.addImage(imgData, 'PNG', 0, 0, 1200, 900, '', 'FAST');
      
      const dateStr = new Date().toISOString().slice(0, 10);
      const recipientNameSafe = (certificate.recipientName || certificate.name || 'Certificate').replace(/[^a-zA-Z0-9]/g, '_');
      const certIdSafe = (certificate.certificateNumber || certificate._id || '').replace(/[^a-zA-Z0-9]/g, '_');
      
      pdf.save(`${t('certificateViewer.pdf.fileNamePrefix', { ns: 'common', defaultValue: 'AEU_Diploma'})}_${recipientNameSafe}_${certIdSafe}_${dateStr}.pdf`); //i18n for prefix

    } catch (error) {
      console.error(t('certificateViewer.pdf.generationError.general'), error); // i18n
      alert(t('certificateViewer.pdf.generationError.alert')); // i18n
    } finally {
      // Hide loading indicator here if you showed one
    }
  };

  // Ensure consistent background color for the page itself, if desired
  const backgroundColor = '#FFFEF0'; // Used in getCertificateSVG and PDF generation

  if (loading) {
    return <div className="mt-6"><LoadingSpinner message={t('certificateViewer.loading')} /></div>;
  }

  if (error) {
    return <div className="mt-6"><AlertMessage type="error" message={{ title: t('certificateViewer.errorTitle'), details: error }} /></div>;
  }

  return (
    <div className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8" style={{ backgroundColor: '#F0F0F0' /* Light grey page background */ }}>
      <div className="px-4 py-5 sm:px-0">
        <h2 className="text-3xl font-bold leading-tight text-gray-900">
          {t('certificateViewer.pageTitle')} 
        </h2>
      </div>

      {certificateSvgUrl ? (
        <div className="mt-6 bg-white shadow-xl overflow-hidden sm:rounded-lg">
          <div className="px-4 py-5 border-b border-gray-200 sm:px-6 flex flex-wrap justify-between items-center gap-4">
            <div>
              <h3 className="text-xl leading-6 font-semibold text-gray-900">
                {t('certificateViewer.previewTitle')}
              </h3>
              <p className="mt-1 max-w-2xl text-sm text-gray-500">
                {t('certificateViewer.previewSubtitle')}
              </p>
            </div>
            <div className="flex space-x-3">
              <button 
                onClick={handleDownloadPDF}
                className="inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-green-600 hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 transition ease-in-out duration-150"
              >
                {t('certificateViewer.downloadPdfButton')}
              </button>
              <a
                href={certificateSvgUrl}
                download={`${t('certificateViewer.svg.fileNamePrefix', { ns: 'common', defaultValue: 'AEU_Diploma'})}_${(certificate.recipientName || certificate.name || 'Certificate').replace(/[^a-zA-Z0-9]/g, '_')}.svg`}
                className="inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transition ease-in-out duration-150"
              >
                {t('certificateViewer.downloadSvgButton')}
              </a>
            </div>
          </div>
          <div className="certificate-preview-container p-4 flex justify-center bg-gray-50" style={{ backgroundColor: backgroundColor /* Match SVG background for seamless preview */ }}>
            <div className="certificate-preview-wrapper max-w-full overflow-auto shadow-lg" style={{ width: '1200px', height: '900px' }}>
              <img
                src={certificateSvgUrl}
                alt={t('certificateViewer.previewAltText')}
                className="certificate-preview w-full h-full object-contain"
              />
            </div>
          </div>
        </div>
      ) : (
        <div className="mt-6">
          <AlertMessage type="info" message={{ title: t('certificateViewer.noCertificateTitle'), details: t('certificateViewer.noCertificateDetails') }} />
        </div>
      )}
    </div>
  );
};

export default CertificateViewerPage;
